return [
  { json: { ticker: 'GC=F', name: 'Gold' } },
  { json: { ticker: 'SI=F', name: 'Silver' } },
  { json: { ticker: 'BTC-USD', name: 'Bitcoin' } },
  { json: { ticker: '%5ETNX', name: 'US 10-Year Yield' } },
  { json: { ticker: '%5EGSPC', name: 'S&P 500' } }
];

const items = $input.all();
const data = {};

for (const item of items) {
  try {
    const res = JSON.parse(item.json.data);
    const result = res.chart.result[0];
    const ticker = result.meta.symbol;
    const prices = result.indicators.quote[0].close.filter(p => p !== null);

    const current = result.meta.regularMarketPrice || prices[prices.length - 1];
    const previous = prices[prices.length - 2] || current;
    const changePercent = ((current - previous) / previous) * 100;

    data[ticker] = {
      price: current.toFixed(2),
      change: changePercent.toFixed(2)
    };
  } catch (e) {
    // Ignore errors for individual tickers
  }
}

// Calculate Gold/Silver ratio
let goldSilverRatio = 'N/A';
if (data['GC=F'] && data['SI=F']) {
  goldSilverRatio = (parseFloat(data['GC=F'].price) / parseFloat(data['SI=F'].price)).toFixed(2);
}

// Validation: halt if S&P 500 price missing
if (data['^GSPC']?.price === 'N/A') {
  throw new Error('S&P 500 data unavailable');
}

return {
  json: {
    gold_price: data['GC=F'] ? data['GC=F'].price : 'N/A',
    gold_change: data['GC=F'] ? data['GC=F'].change : '0.00',
    silver_price: data['SI=F'] ? data['SI=F'].price : 'N/A',
    silver_change: data['SI=F'] ? data['SI=F'].change : '0.00',
    gold_silver_ratio: goldSilverRatio,
    btc_price: data['BTC-USD'] ? data['BTC-USD'].price : 'N/A',
    btc_change: data['BTC-USD'] ? data['BTC-USD'].change : '0.00',
    bond_yield: data['^TNX'] ? data['^TNX'].price : 'N/A',
    bond_change: data['^TNX'] ? data['^TNX'].change : '0.00',
    sp500_price: data['^GSPC'] ? data['^GSPC'].price : 'N/A',
    sp500_change: data['^GSPC'] ? data['^GSPC'].change : '0.00',
    timestamp: new Date().toISOString()
  }
};

let response = $input.first().json.response || '';

// 1. Strip out DeepSeek <think> reasoning blocks
response = response.replace(/<think>[\s\S]*?<\/think>/gi, '').trim();

// 2. Implement safety cutoff for raw text to prevent HTML tag clipping
if (response.length > 3800) {
  response = response.substring(0, 3800) + '\n\n... (Report truncated due to size limits)';
}

// 3. Escape HTML and format Markdown bold
const cleanResponse = response
  .replace(/&/g, '&amp;')
  .replace(/</g, '&lt;')
  .replace(/>/g, '&gt;')
  .replace(/\*\*(.*?)\*\*/g, '<strong>$1</strong>')
  .replace(/^### (.*?)$/gm, '<strong>$1</strong>');

return {
  json: {
    telegramText: `📊 <strong>DAILY MACRO MARKET SENTINEL REPORT</strong>\n\n${cleanResponse}`
  }
};

